class Cooldown {
  constructor(duration) {
    this.duration = duration; // cooldown duration in milliseconds
    this.lastActivated = 0; // timestamp of the last activation
  }

  isReady() {
    return Date.now() - this.lastActivated >= this.duration;
  }

  activate() {
    this.lastActivated = Date.now();
  }
}

// Example usage
const cooldown = new Cooldown(3000); // 3-second cooldown

// Simulate user interaction
