  if (cooldown.isReady()) {
    console.log("Interaction is ready.");
    cooldown.activate(); // reset cooldown
  } else {
    console.log("Cooldown not ready yet. Try again in", Math.ceil((cooldown.duration - (Date.now() - cooldown.lastActivated)) / 1000), "seconds.");
  }
}

