Here's the corrected code:

```objc
- (void)segmentControlChanged:(HMSegmentedControl *)sender {
    UIViewController *oldViewController = [self.childViewControllers firstObject];
    UIViewController *newViewController = [self.childViewControllers objectAtIndex:sender.selectedSegmentIndex];

    newViewController.view.frame = self.containerView.bounds;

    [self transitionFromViewController:oldViewController
                          toViewController:newViewController
                                duration:0.5
                                options:UIViewAnimationOptionTransitionCrossDissolve
                             animations:^{
                                 // Add any animations here if needed
                             }
                           completion:^(BOOL finished) {
                               [newViewController didMoveToParentViewController:self];
                               [oldViewController removeFromParentViewController];
                           }];
}
```

This way, you're simply switching between the two existing child view controllers with an animation, without adding any extra view controllers to the hierarchy.

